// Brouwgilde Breda logo components — embedded base64, no external files needed

// Right side: "Brouwgilde Breda" text + single hop cone
const RIGHT_GREEN = 'data:image/png;base64,'
const RIGHT_WHITE = 'data:image/png;base64,'

// Three decorative hop cones (left side of full logo)
const HOPS = 'data:image/png;base64,'

// Full horizontal logo (both sides)
const FULL_GREEN = 'data:image/png;base64,'
const FULL_WHITE = 'data:image/png;base64,'

/** Main logo mark — text + hop — green version (for light backgrounds) */
export function LogoGreen({ style, className }) {
  return <img src={RIGHT_GREEN} alt="Brouwgilde Breda" style={{ display: 'block', ...style }} className={className} />
}

/** Main logo mark — text + hop — white version (for dark backgrounds) */
export function LogoWhite({ style, className }) {
  return <img src={RIGHT_WHITE} alt="Brouwgilde Breda" style={{ display: 'block', ...style }} className={className} />
}

/** Three decorative hop cones */
export function HopsDecoration({ style, className }) {
  return <img src={HOPS} alt="" aria-hidden="true" style={{ display: 'block', ...style }} className={className} />
}

/** Full wide logo — green */
export function LogoFullGreen({ style, className }) {
  return <img src={FULL_GREEN} alt="Brouwgilde Breda" style={{ display: 'block', ...style }} className={className} />
}

/** Full wide logo — white */
export function LogoFullWhite({ style, className }) {
  return <img src={FULL_WHITE} alt="Brouwgilde Breda" style={{ display: 'block', ...style }} className={className} />
}
